      CHARACTER*4 IDEFVO
      CHARACTER*4 IBUGS2
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGS2.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPVCAR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IDEFVA,IDEFVO
   53 FORMAT('IDEFVA,IDEFVO = ',A4,1X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)NUMARG
   54 FORMAT('NUMARG = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,NUMARG
      WRITE(ICOUT,56)I,IHARG(I)
   56 FORMAT('I,IHARG(I) = ',I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.NE.2)GO TO 9000
!
      IF(IHARG(2).EQ.'AUTO')GO TO 1150
      IF(IHARG(2).EQ.'DEFA')GO TO 1150
      IF(IHARG(2).EQ.'FIXE')GO TO 1160
      IF(IHARG(2).EQ.'VARI')GO TO 1170
      IF(IHARG(2).EQ.'OPEN')GO TO 1180
      IF(IHARG(2).EQ.'CLOS')GO TO 1190
      GO TO 1150
!
 1150 CONTINUE
      IVCARR=IDEFVA
      IVCOPN=IDEFVO
      GO TO 2000
!
 1160 CONTINUE
      IVCARR='FIXE'
      GO TO 2000
!
 1170 CONTINUE
      IVCARR='VARI'
      GO TO 2000
!
 1180 CONTINUE
      IVCOPN='OPEN'
      GO TO 2000
!
 1190 CONTINUE
      IVCOPN='CLOS'
      GO TO 2000
!
 2000 CONTINUE
      IFOUND='YES'
